const { normalizeContent } = require('./md-parse');

function buildImportStub(llm) {
    return [
        '<!-- Managed by soft-harness. Do not edit this file directly. -->',
        `<!-- Source: .harness/HARNESS.md + .harness/llm/${llm}.md -->`,
        '<!-- Regenerate: soft-harness sync -->',
        '',
        '@.harness/HARNESS.md',
        `@.harness/llm/${llm}.md`,
        ''
    ].join('\n');
}

function buildConcatStub(llm, commonContent, llmContent) {
    return [
        '<!-- Managed by soft-harness. Do not edit this file directly. -->',
        `<!-- Source: .harness/HARNESS.md + .harness/llm/${llm}.md -->`,
        '<!-- Regenerate: soft-harness sync -->',
        '<!-- BEGIN HARNESS.md -->',
        '',
        normalizeContent(commonContent || '').trim(),
        '',
        '<!-- END HARNESS.md -->',
        `<!-- BEGIN llm/${llm}.md -->`,
        '',
        normalizeContent(llmContent || '').trim(),
        '',
        `<!-- END llm/${llm}.md -->`,
        ''
    ].join('\n').replace(/\n{3,}/g, '\n\n');
}

function parseConcatStub(content) {
    const normalized = normalizeContent(content || '');
    const blocks = [];
    const outside = [];
    const lines = normalized.split('\n');
    let index = 0;

    while (index < lines.length) {
        const beginMatch = /^<!-- BEGIN ([^>]+) -->$/.exec(lines[index].trim());
        if (!beginMatch) {
            outside.push(lines[index]);
            index += 1;
            continue;
        }

        const blockLines = [];
        const blockPath = beginMatch[1];
        index += 1;
        while (index < lines.length && lines[index].trim() !== `<!-- END ${blockPath} -->`) {
            blockLines.push(lines[index]);
            index += 1;
        }
        blocks.push({
            path: blockPath,
            content: blockLines.join('\n').trim()
        });
        if (index < lines.length) {
            index += 1;
        }
    }

    const outsideContent = outside.join('\n')
        .replace(/^<!-- Managed by soft-harness.*$/m, '')
        .replace(/^<!-- Source:.*$/m, '')
        .replace(/^<!-- Regenerate:.*$/m, '')
        .trim();

    return {
        blocks,
        outside: outsideContent
    };
}

function extractImportStubDelta(content) {
    const normalized = normalizeContent(content || '');
    const lines = normalized.split('\n');
    const extra = [];

    for (const line of lines) {
        if (line.startsWith('<!-- Managed by soft-harness')) {
            continue;
        }
        if (line.startsWith('<!-- Source:')) {
            continue;
        }
        if (line.startsWith('<!-- Regenerate:')) {
            continue;
        }
        if (line.startsWith('@.harness/')) {
            continue;
        }
        extra.push(line);
    }

    return extra.join('\n').trim();
}

module.exports = {
    buildConcatStub,
    buildImportStub,
    extractImportStubDelta,
    parseConcatStub
};
